<?php declare(strict_types=1); namespace App\Models; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\HasMany; final class BtaqProgram extends Model{protected $fillable=['name','code','description','is_active','sort_order','uses_reading_progress','uses_memorization_progress','uses_tajwid_assessment','uses_makhraj_assessment','notes']; protected function casts():array{return ['is_active'=>'boolean','uses_reading_progress'=>'boolean','uses_memorization_progress'=>'boolean','uses_tajwid_assessment'=>'boolean','uses_makhraj_assessment'=>'boolean'];} public function levels():HasMany{return $this->hasMany(BtaqLevel::class);} public function groups():HasMany{return $this->hasMany(BtaqGroup::class);} }
